return items.map(item => {

  let signals = [];
  const review = (item.json.review_text || "").toLowerCase();

  // Delivery Issues
  if (
    review.includes("late delivery") ||
    review.includes("arrived late") ||
    review.includes("shipping delay") ||
    review.includes("took too long")
  ) {
    signals.push("delivery_delay");
  }

  // Returns / Refund Issues
  if (
    review.includes("refund") ||
    review.includes("return") ||
    review.includes("money back") ||
    review.includes("refund denied")
  ) {
    signals.push("returns_friction");
  }

  // Quality / Durability Issues
  if (
    review.includes("fell apart") ||
    review.includes("doesn't last") ||
    review.includes("broke") ||
    review.includes("torn") ||
    review.includes("poor quality")
  ) {
    signals.push("product_durability_issue");
  }

  // Sizing Issues
  if (
    review.includes("run small") ||
    review.includes("too tight") ||
    review.includes("too loose") ||
    review.includes("size up")
  ) {
    signals.push("sizing_issue");
  }

  // Support Issues
  if (
    review.includes("no response") ||
    review.includes("customer service") ||
    review.includes("support didn't")
  ) {
    signals.push("support_issue");
  }

  return {
    json: {
      ...item.json,
      frictionSignals: signals
    }
  };

});

parameters.text:
=Analyze the following ecommerce friction data:

Brand: {{$json.brand}}
Product: {{$json.productName}}
ASIN: {{$json.asin}}
Friction Signals: {{$json.frictionSignals}}
Review Rating: {{$json.reviewRating}}
Review Header: {{$json.review_header}}
Review Text: {{$json.reviewText}}


Classify:

1. Friction category (Checkout / Delivery / Returns / Support / Product)
2. Estimated revenue impact (Low / Medium / High)
3. Numerical impact score (0-100)
4. Confidence score (0-100)
5. Short reasoning

Respond strictly in this JSON format:

{
  "brand": "",
  "productName": "",
  "asin": "",
  "reviewHeader": "",
  "reviewText": "",
  "reviewRating": 0,
  "frictionSignals": [],
  "frictionCategory": "",
  "estimatedImpact": "",
  "impactScore": 0,
  "confidenceScore": 0,
  "reasoning": ""
}

