return items.map(item => {

  const data = item.json.output;

  let frictionWeight = 0;

  if (data.frictionSignals?.includes("checkout_failure")) frictionWeight += 40;
  if (data.frictionSignals?.includes("delivery_delay")) frictionWeight += 25;
  if (data.frictionSignals?.includes("returns_friction")) frictionWeight += 20;
  if (data.frictionSignals?.includes("support_issue")) frictionWeight += 15;
  if (data.frictionSignals?.includes("sizing_issue")) frictionWeight += 20;
  if (data.frictionSignals?.includes("product_durability_issue")) frictionWeight += 30;

  const impactComponent = (data.impactScore || 0) * 0.7;

  const finalScore = Math.round(frictionWeight + impactComponent);

  return {
    json: {
      ...data,
      correlatedScore: finalScore
    }
  };

});
